// // This latch resets asynchronously on CLK rising edge and synchronously on RST rising edge
module d_latch(  
    input D,  
    input CLK,  
    input RST,  
    output reg Q  
);  
    always @(posedge CLK or posedge RST) begin  
        if (RST)  
            Q <= 0;  
        else  
            Q <= D;  
    end  
endmodule
